const data = $input.first().json;
const results = data.results || [];
return results.map(r => ({ json: r }));

const volId = $('Webhook: iCal Feed').first().json.query?.vol;
if (!volId) {
  return [{ json: { ics: 'ERROR:MISSING_VOL_PARAM' }}];
}

const records = $input.all();
const now = new Date();
const stamp = now.toISOString().replace(/[-:.]/g,'').slice(0,15) + 'Z';

// Helper: extract value from lookup field (object {id, value} or plain string)
const val = (field) => {
  if (!field) return null;
  const v = Array.isArray(field) ? field[0] : field;
  return (v && typeof v === 'object') ? v.value : v;
};

// Convert ISO datetime string to iCal format: 20260318T143000
const toIcal = (dt) => {
  if (!dt) return null;
  return dt.replace(/[-:]/g,'').replace('+00:00','').replace('.000','').slice(0,15);
};

const lines = [
  'BEGIN:VCALENDAR',
  'VERSION:2.0',
  'PRODID:-//CTR-CRM//Conversations to Remember//EN',
  'CALSCALE:GREGORIAN',
  'METHOD:PUBLISH',
  'X-WR-CALNAME:My CTR-CRM Schedule',
  'X-WR-TIMEZONE:America/Los_Angeles',
];

for (const item of records) {
  const row = item.json;
  if (!row || !row.id) continue;

  const status = (row.attendance_status && typeof row.attendance_status === 'object')
    ? row.attendance_status.value
    : row.attendance_status || '';
  if (status === 'cancelled') continue;

  const rawStart = val(row.instance_start);
  const rawEnd   = val(row.instance_end);
  const rawDate  = val(row.instance_date);

  if (!rawStart) continue;

  const dtStart = toIcal(rawStart);
  const dtEnd   = toIcal(rawEnd) || dtStart;

  const volName = (row.volunteer && row.volunteer[0]) ? row.volunteer[0].value : 'Volunteer';
  const summary = 'CTR-CRM Visit' + (rawDate ? ' - ' + rawDate.slice(0,10) : '');
  const desc    = 'Volunteer: ' + volName + ' | Status: ' + status;

  lines.push('BEGIN:VEVENT');
  lines.push('DTSTART:' + dtStart);
  lines.push('DTEND:' + dtEnd);
  lines.push('SUMMARY:' + summary);
  lines.push('DESCRIPTION:' + desc);
  lines.push('UID:attendance-' + row.id + '@ctr-crm');
  lines.push('DTSTAMP:' + stamp);
  lines.push('END:VEVENT');
}

lines.push('END:VCALENDAR');
return [{ json: { ics: lines.join('\r\n') }}];

